import{_ as e,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as d,o as r,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Ограничения частоты загрузок для пользователей","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Safety/user-rate-limits.md","filePath":"ru-RU/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),s={name:"ru-RU/Safety/user-rate-limits.md"};function o(p,t,n,h,c,m){return r(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="ограничения-частоты-загрузок-для-пользователеи" tabindex="-1">Ограничения частоты загрузок для пользователей <a class="header-anchor" href="#ограничения-частоты-загрузок-для-пользователеи" aria-label="Permalink to &quot;Ограничения частоты загрузок для пользователей&quot;">​</a></h1><p>User rate limits управляют тем, как часто обычные пользователи или посетители могут загружать файлы с главной страницы. Это помогает защитить публичную страницу загрузки от злоупотреблений.</p><p>Функция влияет только на загрузки с главной страницы. Загрузки администратора и загрузки через API Tokens не ограничиваются user rate limits.</p><h2 id="где-это-настраивается" tabindex="-1">Где это настраивается <a class="header-anchor" href="#где-это-настраивается" aria-label="Permalink to &quot;Где это настраивается&quot;">​</a></h2><p>Откройте админ-панель и перейдите в:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+e+'" alt="Настройки user rate limit" loading="lazy"></p><h2 id="включение-rate-limits" tabindex="-1">Включение rate limits <a class="header-anchor" href="#включение-rate-limits" aria-label="Permalink to &quot;Включение rate limits&quot;">​</a></h2><p>После включения <code>Enable Rate Limits</code> ImgBed отслеживает недавние загрузки по IP-адресу отправителя.</p><p>Значения по умолчанию:</p><table tabindex="0"><thead><tr><th>Настройка</th><th>По умолчанию</th><th>Описание</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>Насколько далеко назад считаются записи загрузок.</td></tr><tr><td>Max file count</td><td>20</td><td>Максимальное число файлов в detection window.</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>Максимальный размер одного файла.</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>Максимальный общий размер загрузок в detection window.</td></tr></tbody></table><p>Например, с окном 1,5 часа, 20 файлами, 20 MB на файл и 200 MB всего загрузки с того же IP блокируются, как только превышен любой настроенный лимит.</p><h2 id="исключение-типов-фаилов" tabindex="-1">Исключение типов файлов <a class="header-anchor" href="#исключение-типов-фаилов" aria-label="Permalink to &quot;Исключение типов файлов&quot;">​</a></h2><p><code>Excluded upload file types</code> блокирует обычным пользователям или посетителям загрузку выбранных категорий файлов.</p><p>Доступные категории:</p><table tabindex="0"><thead><tr><th>Тип</th><th>Описание</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif и похожие файлы изображений</td></tr><tr><td>Videos</td><td>mp4, webm, mov и похожие видеофайлы</td></tr><tr><td>Audio</td><td>mp3, flac, wav и похожие аудиофайлы</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx и похожие документы</td></tr><tr><td>Other</td><td>Файлы вне этих категорий, например zip, rar, exe, apk</td></tr></tbody></table><p>По умолчанию категория не выбрана, то есть она разрешена.</p><p>Нажатие на категорию подсвечивает ее, а это означает, что тип заблокирован.</p><p>Если выбрать <code>Other</code>, посетители, загружающие zip или rar, будут заблокированы и увидят сообщение, что этот тип файла не поддерживается.</p><h2 id="сообщения-о-блокировке" tabindex="-1">Сообщения о блокировке <a class="header-anchor" href="#сообщения-о-блокировке" aria-label="Permalink to &quot;Сообщения о блокировке&quot;">​</a></h2><p>Когда срабатывает лимит, пользователи видят соответствующее сообщение:</p><p><img src="'+a+'" alt="Сообщение о слишком частой загрузке" loading="lazy"></p><table tabindex="0"><thead><tr><th>Сценарий</th><th>Значение сообщения</th></tr></thead><tbody><tr><td>Один файл слишком большой</td><td>Файл слишком большой, его стоит сжать перед загрузкой.</td></tr><tr><td>Тип файла заблокирован</td><td>Этот тип файла не поддерживается. Уберите его и попробуйте снова.</td></tr><tr><td>Загрузки слишком частые</td><td>Недавние загрузки слишком частые, показано время повторной попытки.</td></tr><tr><td>Общий размер слишком большой</td><td>Суммарный размер недавних загрузок слишком велик, показано время повторной попытки.</td></tr></tbody></table><h2 id="когда-включать" tabindex="-1">Когда включать <a class="header-anchor" href="#когда-включать" aria-label="Permalink to &quot;Когда включать&quot;">​</a></h2><p>Включите user rate limits, если ваша главная страница загрузки доступна публично.</p><p>Типичные причины:</p><ul><li>вы опасаетесь массовых автоматизированных загрузок;</li><li>хотите ограничить большие загрузки от посетителей;</li><li>хотите разрешить обычным пользователям загружать только изображения, а не архивы или установщики;</li><li>хотите оставить публичную загрузку доступной, но контролировать расход ресурсов.</li></ul><p>Если сайт только для вас или загружать могут только администраторы, это можно оставить выключенным.</p>',28)])])}const f=d(s,[["render",o]]);export{_ as __pageData,f as default};
